const { Manifold, CrossSection, label } = api;

const segments = 48;

// King profile — revolve around Z axis (profile Y = height becomes Z after revolve).
// Profile traces from center-bottom outward, up to top.
// In 2D profile: X = radius, Y = height (becomes Z after revolve)
const profile = [
  // Tiered base
  [0, 0], // center bottom
  [5.5, 0], // base outer bottom
  [5.5, 0.8], // base outer rim
  [4.5, 1.5], // step inward
  [5.0, 2.0], // second tier outer
  [5.0, 2.8], // second tier top
  [4.0, 3.5], // base narrows to stem

  // Stem — slender column
  [3.2, 4.5], // lower stem
  [2.8, 7.0], // mid stem taper
  [2.5, 11.0], // upper stem
  [2.6, 13.0], // slight swell

  // Crown collar — flares outward near top
  [2.5, 14.5], // below collar
  [4.0, 16.0], // collar flare outward
  [4.2, 17.0], // collar top outer
  [3.8, 17.8], // collar lip

  // Short neck above collar
  [2.8, 18.5], // neck
  [3.0, 20.0], // top of neck / base of cross mount

  // Top knob for cross base
  [2.5, 21.0], // shoulder
  [2.0, 22.0], // top of body
  [0, 22.0], // center top
];

const bodyCS = CrossSection.ofPolygons([profile]);
const body = Manifold.revolve(bodyCS, segments);

// Cross finial — two rectangular bars forming a cross
// Vertical bar: 1.5 wide, 1.5 deep, 7 tall, centered at top of body at z=22
const crossV = Manifold.cube([1.5, 1.5, 7], true).translate([0, 0, 22 + 3.5]);
// Horizontal bar: 7 wide, 1.5 deep, 1.5 tall, positioned 2 units up the vertical bar
const crossH = Manifold.cube([7, 1.5, 1.5], true).translate([0, 0, 22 + 2.5]);

const cross = crossV.add(crossH);

return label(body, 'body').add(label(cross, 'cross'));
